sql:
SELECT baby_id, COUNT(DISTINCT device_id) AS number_of_devices
FROM device_data
GROUP BY baby_id;

SELECT *
FROM device_data
WHERE NOT EXISTS (SELECT 1 FROM wearable_devices WHERE wearable_devices.device_id = device_data.device_id);

SELECT COUNT(*) AS total_growth_charts
FROM growth_charts
WHERE age_group_id = 1;

SELECT b.name, gr.measurement_date
FROM babies b
JOIN growth_records gr ON b.baby_id = gr.baby_id;

